 1→import { decode, getToken } from "@auth/core/jwt";
 2→import type { JWT } from "@auth/core/jwt";
 3→
 4→export const SESSION_CONFIG = {
 5→  maxAge: 8 * 60 * 60,
 6→  updateAge: 30 * 60,
 7→};
 8→
 9→export function getAuthSecret(): string | null {
10→  return process.env.AUTH_SECRET ?? process.env.NEXTAUTH_SECRET ?? null;
11→}
12→
13→export function getAuthBaseUrl(): string | null {
14→  const raw = [process.env.AUTH_URL, process.env.NEXTAUTH_URL].find(
15→    (value): value is string => typeof value === "string" && value.trim().length > 0,
16→  );
17→  return raw?.trim() ?? null;
18→}
19→
20→export function isSecureRequest(): boolean {
21→  const authUrl = getAuthBaseUrl() ?? "";
22→  if (typeof authUrl === "string" && authUrl.startsWith("https://")) return true;
23→  return process.env.NODE_ENV === "production";
24→}
25→
26→export function getSessionCookieName(): string {
27→  return isSecureRequest() ? "__Secure-authjs.session-token" : "authjs.session-token";
28→}
29→
30→export async function getAuthToken(request: Request): Promise<JWT | null> {
31→  const secret = getAuthSecret();
32→  if (!secret) return null;
33→  const cookieName = getSessionCookieName();
34→  const secureCookie = isSecureRequest();
35→  const salt = cookieName;
36→  const authHeader = request.headers.get("authorization");
37→  if (authHeader?.toLowerCase().startsWith("bearer ")) {
38→    const raw = authHeader.slice(7).trim();
39→    const decoded = await decode({ token: raw, secret, salt });
40→    return decoded ?? null;
41→  }
42→  return await getToken({ req: request, secret, salt, cookieName, secureCookie });
43→}
44→
45→export async function requireUser(request: Request): Promise<{ id: string; token: JWT } | null> {
46→  const token = await getAuthToken(request);
47→  if (!token) return null;
48→  const email = typeof token.email === "string" ? token.email.toLowerCase().trim() : null;
49→  const uid = (token as JWT & { uid?: unknown }).uid;
50→  const normalizedUid = typeof uid === "string" ? uid.trim() : null;
51→  const sub = typeof token.sub === "string" ? token.sub.trim() : null;
52→  const id = email || normalizedUid || sub;
53→  if (!id) return null;
54→  return { id, token };
55→}
