 1→import { createHash } from "node:crypto";
 2→import { query } from "./db.js";
 3→import { logSecurityEvent } from "./securityAudit.js";
 4→
 5→function hashKey(input: string): string {
 6→  return createHash("sha256").update(input.trim()).digest("hex");
 7→}
 8→
 9→function windowStartIso(windowSeconds: number, now = Date.now()): string {
10→  const bucket = Math.floor(now / (windowSeconds * 1000)) * windowSeconds * 1000;
11→  return new Date(bucket).toISOString();
12→}
13→
14→export async function consumeRateLimit(input: {
15→  route: string;
16→  key: string;
17→  windowSeconds: number;
18→  max: number;
19→  request?: Request | null;
20→  userId?: string | null;
21→}): Promise<{ allowed: boolean; remaining: number; retryAfterSeconds: number; count: number }> {
22→  const route = input.route.trim();
23→  const keyHash = hashKey(input.key);
24→  const startedAt = windowStartIso(input.windowSeconds);
25→  const result = await query<{ request_count: number }>(
26→    `INSERT INTO api_rate_limits (route, key_hash, window_start, request_count, updated_at)
27→     VALUES ($1, $2, $3::timestamptz, 1, NOW())
28→     ON CONFLICT (route, key_hash, window_start)
29→     DO UPDATE SET
30→       request_count = api_rate_limits.request_count + 1,
31→       updated_at = NOW()
32→     RETURNING request_count`,
33→    [route, keyHash, startedAt],
34→  );
35→
36→  const count = Number(result.rows[0]?.request_count ?? 0);
37→  const allowed = count <= input.max;
38→  const elapsedSeconds = Math.floor((Date.now() - new Date(startedAt).getTime()) / 1000);
39→  const retryAfterSeconds = Math.max(1, input.windowSeconds - elapsedSeconds);
40→
41→  if (!allowed) {
42→    await logSecurityEvent({
43→      eventType: "api_rate_limited",
44→      userId: input.userId ?? null,
45→      request: input.request,
46→      details: {
47→        route,
48→        limit: input.max,
49→        count,
50→        retryAfterSeconds,
51→      },
52→    });
53→  }
54→
55→  return {
56→    allowed,
57→    remaining: Math.max(0, input.max - count),
58→    retryAfterSeconds,
59→    count,
60→  };
61→}
