 3→export type SecurityAuditEventType =
 4→  | "login_success"
 5→  | "login_failure"
 6→  | "logout"
 7→  | "session_expired"
 8→  | "session_revoked"
 9→  | "account_locked"
10→  | "account_unlocked"
11→  | "role_changed"
12→  | "remote_wipe_triggered"
13→  | "remote_wipe_executed"
14→  | "data_export"
15→  | "privacy_request"
16→  | "privacy_erasure"
17→  | "submission_flagged"
18→  | "submission_rejected"
19→  | "admin_review"
20→  | "api_rate_limited"
21→  | "idempotency_conflict"
22→  | "suspicious_activity";
