24→function normalizeIp(raw: string | null): string | null {
25→  const value = raw?.split(",")[0]?.trim();
26→  if (!value) return null;
27→  return value.replace(/^\[|\]$/g, "");
28→}
29→
30→function requestMetadata(request: Request | null | undefined): { ip: string | null; userAgent: string | null } {
31→  if (!request) return { ip: null, userAgent: null };
32→  return {
33→    ip: normalizeIp(
34→      request.headers.get("x-vercel-forwarded-for") ??
35→        request.headers.get("x-forwarded-for") ??
36→        request.headers.get("x-real-ip"),
37→    ),
38→    userAgent: request.headers.get("user-agent"),
39→  };
40→}
41→
42→export async function logSecurityEvent(input: {
43→  eventType: SecurityAuditEventType;
44→  userId?: string | null;
45→  request?: Request | null;
46→  details?: Record<string, unknown> | null;
47→}): Promise<void> {
48→  const meta = requestMetadata(input.request);
49→  await query(
50→    `INSERT INTO security_audit_log (event_type, user_id, ip_address, user_agent, details)
51→     VALUES ($1, $2, $3, $4, $5::jsonb)`,
52→    [
53→      input.eventType,
54→      input.userId ?? null,
55→      meta.ip,
56→      meta.userAgent,
57→      JSON.stringify(input.details ?? {}),
58→    ],
59→  );
60→}
