 1→export interface CategorySetDiff {
 2→  expected: string[];
 3→  actual: string[];
 4→  missing: string[];
 5→  extra: string[];
 6→  ok: boolean;
 7→}
 8→
 9→function uniqueSorted(values: string[]): string[] {
10→  return Array.from(new Set(values.map((value) => value.trim()).filter((value) => value.length > 0))).sort((a, b) => a.localeCompare(b));
11→}
12→
13→export function parseConstraintCategories(definition: string | null | undefined): string[] {
14→  if (typeof definition !== "string" || definition.trim().length === 0) return [];
15→  const values: string[] = [];
16→  const regex = /'((?:[^']|'')+)'/g;
17→  let match: RegExpExecArray | null = regex.exec(definition);
18→  while (match) {
19→    const value = (match[1] ?? "").replace(/''/g, "'").trim();
20→    if (value.length > 0) values.push(value);
21→    match = regex.exec(definition);
22→  }
23→  return uniqueSorted(values);
24→}
25→
26→export function diffCategorySets(expected: string[], actual: string[]): CategorySetDiff {
27→  const normalizedExpected = uniqueSorted(expected);
28→  const normalizedActual = uniqueSorted(actual);
29→  const expectedSet = new Set(normalizedExpected);
30→  const actualSet = new Set(normalizedActual);
31→
32→  const missing = normalizedExpected.filter((value) => !actualSet.has(value));
33→  const extra = normalizedActual.filter((value) => !expectedSet.has(value));
34→
35→  return {
36→    expected: normalizedExpected,
37→    actual: normalizedActual,
38→    missing,
39→    extra,
40→    ok: missing.length === 0 && extra.length === 0,
41→  };
42→}
