 1→async function digestBytes(buffer: ArrayBuffer): Promise<string> {
 2→  const hash = await crypto.subtle.digest("SHA-256", buffer);
 3→  return Array.from(new Uint8Array(hash))
 4→    .map((byte) => byte.toString(16).padStart(2, "0"))
 5→    .join("");
 6→}
 7→
 8→export async function hashPhoto(file: File): Promise<string> {
 9→  return digestBytes(await file.arrayBuffer());
10→}
11→
12→export async function hashDataUrl(dataUrl: string): Promise<string | null> {
13→  const commaIndex = dataUrl.indexOf(",");
14→  if (commaIndex === -1) return null;
15→  const base64 = dataUrl.slice(commaIndex + 1);
16→  if (!base64) return null;
17→  const bytes = Uint8Array.from(atob(base64), (char) => char.charCodeAt(0));
18→  return digestBytes(bytes.buffer);
19→}
