  1→import { Auth } from "@auth/core";
  2→import Credentials from "@auth/core/providers/credentials";
  3→import Google from "@auth/core/providers/google";
  4→import type { AppProviders } from "@auth/core/providers";
  5→import bcrypt from "bcryptjs";
  6→import type { UserProfile } from "../../../shared/types.js";
  7→import { DEFAULT_AVATAR_PRESET, encodeAvatarPresetImage } from "../../../shared/avatarPresets.js";
  8→import { errorResponse } from "../http.js";
  9→import { getUserProfile, isStorageUnavailableError, upsertUserProfile } from "../storage/index.js";
 10→import { getAuthBaseUrl, getAuthSecret, getSessionCookieName, isSecureRequest, SESSION_CONFIG } from "../../auth.js";
 11→import { inferDefaultDisplayName, normalizeEmail, normalizeIdentifier } from "../../shared/identifier.js";
 12→import { withAbsoluteUrl } from "./requestUrl.js";
 13→import { consumeRateLimit } from "../rateLimit.js";
 14→import { logSecurityEvent } from "../securityAudit.js";
 15→import { captureServerException } from "../sentry.js";
 16→import { logWarn } from "../logger.js";
 17→
 18→const googleClientId = process.env.GOOGLE_CLIENT_ID ?? "";
 19→const googleClientSecret = process.env.GOOGLE_CLIENT_SECRET ?? "";
 20→const LOCKOUT_MAX_ATTEMPTS = 5;
 21→const LOCKOUT_DURATION_MINUTES = 30;
 22→
 23→function extractRequestIp(request: Request | undefined): string | null {
 24→  if (!request) return null;
 25→  const header =
 26→    request.headers.get("x-vercel-forwarded-for") ??
 27→    request.headers.get("x-forwarded-for") ??
 28→    request.headers.get("x-real-ip");
 29→  const value = header?.split(",")[0]?.trim();
 30→  return value || null;
 31→}
 32→
 33→function isBcryptHash(value: string): boolean {
 34→  return /^\$2[aby]\$/.test(value);
 35→}
 36→
 37→async function persistLoginFailure(profile: UserProfile | null, request: Request | undefined, userId: string): Promise<void> {
 38→  if (!profile) {
 39→    await logSecurityEvent({
 40→      eventType: "login_failure",
 41→      userId,
 42→      request,
 43→      details: { reason: "invalid_credentials", hasProfile: false },
 44→    });
 45→    return;
 46→  }
 47→
 48→  const nextCount = (profile.failedLoginCount ?? 0) + 1;
 49→  profile.failedLoginCount = nextCount;
 50→  if (nextCount >= LOCKOUT_MAX_ATTEMPTS) {
 51→    profile.lockedUntil = new Date(Date.now() + LOCKOUT_DURATION_MINUTES * 60 * 1000).toISOString();
 52→  }
 53→  await upsertUserProfile(profile.id, profile);
 54→  await logSecurityEvent({
 55→    eventType: nextCount >= LOCKOUT_MAX_ATTEMPTS ? "account_locked" : "login_failure",
 56→    userId: profile.id,
 57→    request,
 58→    details: {
 59→      failedLoginCount: nextCount,
 60→      lockedUntil: profile.lockedUntil ?? null,
 61→    },
 62→  });
 63→}
 64→
 65→async function clearLoginFailure(profile: UserProfile): Promise<void> {
 66→  if (!profile.failedLoginCount && !profile.lockedUntil) return;
 67→  profile.failedLoginCount = 0;
 68→  profile.lockedUntil = null;
 69→  await upsertUserProfile(profile.id, profile);
 70→}
 71→
 72→const providers: AppProviders = [
 73→  Credentials({
 74→    name: "Credentials",
 75→    credentials: {
 76→      identifier: { label: "Phone or email", type: "text" },
 77→      email: { label: "Email", type: "text" },
 78→      password: { label: "Password", type: "password" },
 79→    },
 80→    async authorize(credentials, request) {
 81→      const rawIdentifier =
 82→        typeof credentials?.identifier === "string"
 83→          ? credentials.identifier
 84→          : typeof credentials?.email === "string"
 85→            ? credentials.email
 86→            : "";
 87→      const normalizedIdentifier = normalizeIdentifier(rawIdentifier);
 88→      const password = typeof credentials?.password === "string" ? credentials.password : "";
 89→
 90→      if (!normalizedIdentifier || !password) return null;
 91→      const identifier = normalizedIdentifier.value;
 92→      const ip = extractRequestIp(request);
 93→      if (ip) {
 94→        const authRate = await consumeRateLimit({
 95→          route: "POST /api/auth/callback/credentials",
 96→          key: `${ip}:${identifier}`,
 97→          windowSeconds: 15 * 60,
 98→          max: 10,
 99→          request,
100→          userId: identifier,
101→        });
102→        if (!authRate.allowed) {
103→          return null;
104→        }
105→      }
106→
107→      const adminEmail = normalizeEmail(process.env.ADMIN_EMAIL);
108→      const adminPassword = process.env.ADMIN_PASSWORD ?? "";
109→      if (adminEmail && adminPassword && normalizedIdentifier.type === "email" && identifier === adminEmail) {
110→        if (!isBcryptHash(adminPassword)) {
111→          logWarn("auth.admin_password_invalid_format", { userId: identifier });
112→          return null;
113→        }
114→        const adminMatch = await bcrypt.compare(password, adminPassword);
115→        if (adminMatch) {
116→          await logSecurityEvent({
117→            eventType: "login_success",
118→            userId: identifier,
119→            request,
120→            details: { method: "credentials_admin" },
121→          });
122→          return { id: identifier, name: "Admin", email: identifier };
123→        }
124→        await logSecurityEvent({
125→          eventType: "login_failure",
126→          userId: identifier,
127→          request,
128→          details: { reason: "invalid_admin_credentials" },
129→        });
130→        return null;
131→      }
132→
133→      const profile = await getUserProfile(identifier);
134→      if (profile?.lockedUntil && new Date(profile.lockedUntil).getTime() > Date.now()) {
135→        await logSecurityEvent({
136→          eventType: "login_failure",
137→          userId: profile.id,
138→          request,
139→          details: { reason: "account_locked", lockedUntil: profile.lockedUntil },
140→        });
141→        return null;
142→      }
143→      if (!profile?.passwordHash) {
144→        await persistLoginFailure(profile ?? null, request, identifier);
145→        return null;
146→      }
147→
148→      const valid = await bcrypt.compare(password, profile.passwordHash);
149→      if (!valid) {
150→        await persistLoginFailure(profile, request, identifier);
151→        return null;
152→      }
153→
154→      await clearLoginFailure(profile);
155→      await logSecurityEvent({
156→        eventType: "login_success",
157→        userId: profile.id,
158→        request,
159→        details: { method: "credentials" },
160→      });
161→
162→      const fallbackName = inferDefaultDisplayName(profile.email ?? profile.phone ?? profile.id);
163→      return { id: profile.id, name: profile.name || fallbackName, email: profile.email ?? undefined };
164→    },
165→  }),
166→];
167→
168→if (googleClientId && googleClientSecret) {
169→  providers.unshift(
170→    Google({
171→      clientId: googleClientId,
172→      clientSecret: googleClientSecret,
173→      token: {
174→        async conform(response) {
175→          // Auth.js v0.33 throws "TODO: Handle OIDC response body error" when
176→          // the token response content-type isn't exactly "application/json".
177→          // Google sometimes returns "application/json; charset=utf-8" which
178→          // triggers this bug. Fix by re-wrapping with a clean content-type.
179→          if (!response.ok) {
180→            const body = await response.text().catch(() => "");
181→            const trimmed = body.length > 1200 ? `${body.slice(0, 1200)}…` : body;
182→            console.error("[auth] google token endpoint response error", {
183→              status: response.status,
184→              statusText: response.statusText,
185→              body: trimmed,
186→            });
187→            return undefined;
188→          }
189→          const contentType = response.headers.get("content-type") ?? "";
190→          if (contentType.includes("application/json")) {
191→            // Re-create response with clean content-type so Auth.js parses it
192→            const body = await response.text();
193→            return new Response(body, {
194→              status: response.status,
195→              headers: { "Content-Type": "application/json" },
196→            });
197→          }
198→          return undefined;
199→        },
200→      },
201→    })
202→  );
203→}
204→
205→const authSecret = getAuthSecret();
206→if (!authSecret) {
207→  throw new Error("AUTH_SECRET (or NEXTAUTH_SECRET) is required for Auth.js");
208→}
209→const authBaseUrl = getAuthBaseUrl();
210→if (!authBaseUrl) {
211→  throw new Error("AUTH_URL (or NEXTAUTH_URL) is required for Auth.js");
212→}
213→
214→export default async function handler(request: Request): Promise<Response> {
215→  try {
216→    const normalizedRequest = await withAbsoluteUrl(request, authBaseUrl);
217→    return await Auth(normalizedRequest, {
218→      providers,
219→      secret: authSecret,
220→      session: { strategy: "jwt", maxAge: SESSION_CONFIG.maxAge, updateAge: SESSION_CONFIG.updateAge },
221→      // Auth.js requires trusted hosts. We already require AUTH_URL and normalize
222→      // relative auth requests against that configured origin before calling Auth().
223→      trustHost: true,
224→      basePath: "/api/auth",
225→      cookies: {
226→        sessionToken: {
227→          name: getSessionCookieName(),
228→          options: {
229→            httpOnly: true,
230→            sameSite: "lax",
231→            path: "/",
232→            secure: isSecureRequest(),
233→          },
234→        },
235→      },
236→      callbacks: {
237→        async signIn({ user, account }) {
238→          const email = normalizeEmail(user?.email);
239→          const adminEmail = normalizeEmail(process.env.ADMIN_EMAIL);
240→          const isAdminAccount = Boolean(email && adminEmail && email === adminEmail);
241→          const provider = account?.provider ?? "unknown";
242→
243→          if (!email) return true;
244→          if (!isAdminAccount && account?.provider !== "google") return true;
245→
246→          try {
247→            if (isAdminAccount) {
248→              const existing = await getUserProfile(email);
249→              if (existing) {
250→                let shouldUpdate = false;
251→                if (!existing.isAdmin) {
252→                  existing.isAdmin = true;
253→                  shouldUpdate = true;
254→                }
255→                if (existing.mapScope !== "global") {
256→                  existing.mapScope = "global";
257→                  shouldUpdate = true;
258→                }
259→                if (shouldUpdate) {
260→                  await upsertUserProfile(email, existing);
261→                }
262→              } else {
263→                const profile: UserProfile = {
264→                  id: email,
265→                  name: user?.name ?? inferDefaultDisplayName(email),
266→                  email,
267→                  phone: null,
268→                  image: encodeAvatarPresetImage(DEFAULT_AVATAR_PRESET),
269→                  avatarPreset: DEFAULT_AVATAR_PRESET,
270→                  occupation: "",
271→                  XP: 0,
272→                  isAdmin: true,
273→                  mapScope: "global",
274→                };
275→                await upsertUserProfile(email, profile);
276→              }
277→              await logSecurityEvent({
278→                eventType: "login_success",
279→                userId: email,
280→                request: normalizedRequest,
281→                details: { method: provider },
282→              });
283→              return true;
284→            }
285→
286→            const existing = await getUserProfile(email);
287→            if (existing) {
288→              if (!existing.mapScope) {
289→                existing.mapScope = "bonamoussadi";
290→                await upsertUserProfile(email, existing);
291→              }
292→              await logSecurityEvent({
293→                eventType: "login_success",
294→                userId: email,
295→                request: normalizedRequest,
296→                details: { method: provider },
297→              });
298→              return true;
299→            }
300→
301→            const profile: UserProfile = {
302→              id: email,
303→              name: user?.name ?? inferDefaultDisplayName(email),
304→              email,
305→              phone: null,
306→              image: encodeAvatarPresetImage(DEFAULT_AVATAR_PRESET),
307→              avatarPreset: DEFAULT_AVATAR_PRESET,
308→              occupation: "",
309→              XP: 0,
310→              mapScope: "bonamoussadi",
311→            };
312→            await upsertUserProfile(email, profile);
313→            await logSecurityEvent({
314→              eventType: "login_success",
315→              userId: email,
316→              request: normalizedRequest,
317→              details: { method: provider },
318→            });
319→            return true;
320→          } catch (error) {
321→            // Do not block OAuth sign-in if profile sync fails.
322→            if (isStorageUnavailableError(error)) {
323→              console.error("[auth] profile sync skipped: storage unavailable", { email, provider });
324→              return true;
325→            }
326→            console.error("[auth] profile sync failed during sign-in", {
327→              email,
328→              provider,
329→              message: error instanceof Error ? error.message : String(error),
330→            });
331→            return true;
332→          }
333→        },
334→        async jwt({ token, user }) {
335→          const adminEmail = normalizeEmail(process.env.ADMIN_EMAIL);
336→          const email = normalizeEmail(user?.email ?? token?.email);
337→          if (adminEmail && email && adminEmail === email) {
338→            (token as { isAdmin?: boolean }).isAdmin = true;
339→            (token as { role?: string }).role = "admin";
340→          } else {
341→            (token as { isAdmin?: boolean }).isAdmin = false;
342→          }
343→          if (email) {
344→            (token as { uid?: string }).uid = email.trim();
345→          } else if (user) {
346→            const id = (user as { id?: string }).id ?? user.email;
347→            if (id) (token as { uid?: string }).uid = id;
348→          }
349→          // Load role from DB if not already set (non-admin users)
350→          if (!(token as { role?: string }).role) {
351→            const uid = (token as { uid?: string }).uid;
352→            if (uid) {
353→              try {
354→                const profile = await getUserProfile(uid);
355→                (token as { role?: string }).role = profile?.role ?? "agent";
356→              } catch {
357→                (token as { role?: string }).role = "agent";
358→              }
359→            }
360→          }
361→          return token;
362→        },
363→        async session({ session, token }) {
364→          if (session.user && token?.uid) {
365→            (session.user as { id?: string }).id = token.uid as string;
366→          }
367→          if (session.user && (token as { isAdmin?: boolean })?.isAdmin !== undefined) {
368→            (session.user as { isAdmin?: boolean }).isAdmin = Boolean((token as { isAdmin?: boolean }).isAdmin);
369→          }
370→          if (session.user && (token as { role?: string })?.role) {
371→            (session.user as { role?: string }).role = (token as { role?: string }).role;
372→          }
373→          return session;
374→        },
375→      },
376→    });
377→  } catch (error) {
378→    if (isStorageUnavailableError(error)) {
379→      return errorResponse("Storage service temporarily unavailable", 503, { code: "storage_unavailable" });
380→    }
381→    captureServerException(error, { route: "auth_handler" });
382→    throw error;
383→  }
384→}
