 10→function isMissingDbObjectError(error: unknown): boolean {
 11→  const pg = error as { code?: unknown; message?: unknown } | null;
 12→  const code = typeof pg?.code === "string" ? pg.code : "";
 13→  if (code === "42P01" || code === "42703") return true;
 14→  const message = typeof pg?.message === "string" ? pg.message.toLowerCase() : "";
 15→  return message.includes("does not exist") || message.includes("undefined table") || message.includes("undefined column");
 16→}
 17→
 18→function requestQueryClause(): string {
 19→  return `
 20→    point_id = $1
 21→    OR user_id = $1
 22→    OR details->>'phone' = $1
 23→    OR lower(COALESCE(details->>'name', '')) = lower($1)
 24→    OR lower(COALESCE(details->>'siteName', '')) = lower($1)
 25→  `;
 26→}
 27→
 28→export async function GET(request: Request): Promise<Response> {
 29→  const auth = await requireUser(request);
 30→  if (!auth) return errorResponse("Unauthorized", 401);
 31→  const viewer = toSubmissionAuthContext(auth);
 32→  if (!viewer?.isAdmin) return errorResponse("Forbidden", 403);
 33→
 34→  const url = new URL(request.url);
 35→  const view = url.searchParams.get("view") ?? "requests";
 36→
 37→  try {
 38→    if (view === "requests") {
 39→      const result = await query<PrivacyRequest>(
 40→        `SELECT id::text, request_type AS "requestType", status, subject_reference AS "subjectReference",
 41→                created_by AS "createdBy", assigned_to AS "assignedTo", notes, resolution_notes AS "resolutionNotes",
 42→                created_at AS "createdAt", updated_at AS "updatedAt"
 43→         FROM privacy_requests
 44→         ORDER BY updated_at DESC
 45→         LIMIT 200`,
 46→      );
 47→      return jsonResponse(result.rows, { status: 200 });
 48→    }
 49→
 50→    return errorResponse("Invalid view", 400);
 51→  } catch (error) {
 52→    if (isMissingDbObjectError(error)) return jsonResponse([], { status: 200 });
 53→    captureServerException(error, { route: "privacy_get" });
 54→    throw error;
 55→  }
