 58→export async function POST(request: Request): Promise<Response> {
 59→  const auth = await requireUser(request);
 60→  if (!auth) return errorResponse("Unauthorized", 401);
 61→  const viewer = toSubmissionAuthContext(auth);
 62→  if (!viewer?.isAdmin) return errorResponse("Forbidden", 403);
 63→
 64→  const url = new URL(request.url);
 65→  const view = url.searchParams.get("view") ?? "requests";
 66→
 67→  let rawBody: unknown;
 68→  try {
 69→    rawBody = await request.json();
 70→  } catch {
 71→    return errorResponse("Invalid JSON body", 400);
 72→  }
 73→
 74→  try {
 75→    if (view === "requests") {
 76→      const validation = privacyRequestSchema.safeParse(rawBody);
 77→      if (!validation.success) {
 78→        return errorResponse(validation.error.issues[0]?.message ?? "Invalid privacy request", 400);
 79→      }
 80→      const body = validation.data;
 81→      const result = await query<PrivacyRequest>(
 82→        `INSERT INTO privacy_requests (request_type, subject_reference, created_by, notes)
 83→         VALUES ($1, $2, $3, $4)
 84→         RETURNING id::text, request_type AS "requestType", status, subject_reference AS "subjectReference",
 85→                   created_by AS "createdBy", assigned_to AS "assignedTo", notes,
 86→                   resolution_notes AS "resolutionNotes", created_at AS "createdAt", updated_at AS "updatedAt"`,
 87→        [body.requestType, body.subjectReference, auth.id, body.notes ?? null],
 88→      );
 89→      await logSecurityEvent({
 90→        eventType: "privacy_request",
 91→        userId: auth.id,
 92→        request,
 93→        details: {
 94→          requestType: body.requestType,
 95→          subjectReference: body.subjectReference,
 96→        },
 97→      });
 98→      return jsonResponse(result.rows[0], { status: 201 });
 99→    }
100→
101→    if (view === "export") {
102→      const validation = privacyActionSchema.safeParse(rawBody);
103→      if (!validation.success) {
104→        return errorResponse(validation.error.issues[0]?.message ?? "Invalid export request", 400);
105→      }
106→      const body = validation.data;
107→      const result = await query(
108→        `SELECT id::text, point_id, user_id, category, latitude, longitude, details, photo_url,
109→                created_at, consent_status, consent_recorded_at, erased_at, erased_by, erasure_reason
110→         FROM point_events
111→         WHERE ${requestQueryClause()}
112→         ORDER BY created_at DESC
113→         LIMIT 200`,
114→        [body.subjectReference],
115→      );
116→      await logSecurityEvent({
117→        eventType: "data_export",
118→        userId: auth.id,
119→        request,
120→        details: { subjectReference: body.subjectReference, rows: result.rowCount ?? 0 },
121→      });
122→      return jsonResponse(
123→        {
124→          subjectReference: body.subjectReference,
125→          rows: result.rows,
126→        },
127→        { status: 200 },
128→      );
129→    }
130→
131→    if (view === "erase") {
132→      const validation = privacyActionSchema.safeParse(rawBody);
133→      if (!validation.success) {
134→        return errorResponse(validation.error.issues[0]?.message ?? "Invalid erasure request", 400);
135→      }
136→      const body = validation.data;
137→      const result = await query(
138→        `UPDATE point_events
139→         SET details = COALESCE(details, '{}'::jsonb)
140→             - 'name'
141→             - 'siteName'
142→             - 'phone'
143→             - 'merchantId'
144→             - 'merchantIdByProvider'
145→             - 'secondPhotoUrl',
146→             photo_url = NULL,
147→             consent_status = 'withdrawn',
148→             erased_at = NOW(),
149→             erased_by = $2,
150→             erasure_reason = $3
151→         WHERE ${requestQueryClause()}
152→         RETURNING id::text`,
153→        [body.subjectReference, auth.id, body.notes ?? "privacy_request"],
154→      );
155→      await logSecurityEvent({
156→        eventType: "privacy_erasure",
157→        userId: auth.id,
158→        request,
159→        details: { subjectReference: body.subjectReference, rows: result.rowCount ?? 0 },
160→      });
161→      return jsonResponse(
162→        {
163→          subjectReference: body.subjectReference,
164→          erasedCount: result.rowCount ?? 0,
165→        },
166→        { status: 200 },
167→      );
168→    }
169→
170→    return errorResponse("Invalid view", 400);
171→  } catch (error) {
172→    captureServerException(error, { route: "privacy_post", view });
173→    throw error;
174→  }
175→}
