177→export async function PATCH(request: Request): Promise<Response> {
178→  const auth = await requireUser(request);
179→  if (!auth) return errorResponse("Unauthorized", 401);
180→  const viewer = toSubmissionAuthContext(auth);
181→  if (!viewer?.isAdmin) return errorResponse("Forbidden", 403);
182→
183→  const url = new URL(request.url);
184→  const view = url.searchParams.get("view") ?? "requests";
185→  if (view !== "requests") return errorResponse("Invalid view", 400);
186→
187→  let body: {
188→    id?: unknown;
189→    status?: unknown;
190→    assignedTo?: unknown;
191→    notes?: unknown;
192→    resolutionNotes?: unknown;
193→  };
194→  try {
195→    body = (await request.json()) as typeof body;
196→  } catch {
197→    return errorResponse("Invalid JSON body", 400);
198→  }
199→
200→  const id = typeof body.id === "string" ? body.id.trim() : "";
201→  const status = typeof body.status === "string" ? body.status.trim().toLowerCase() : "";
202→  const assignedTo = typeof body.assignedTo === "string" ? body.assignedTo.trim() : null;
203→  const notes = typeof body.notes === "string" ? body.notes.trim().slice(0, 1000) : null;
204→  const resolutionNotes = typeof body.resolutionNotes === "string" ? body.resolutionNotes.trim().slice(0, 1000) : null;
205→  if (!id) return errorResponse("Privacy request id is required", 400);
206→  if (!["open", "in_progress", "completed", "rejected"].includes(status)) {
207→    return errorResponse("Invalid privacy request status", 400);
208→  }
209→
210→  try {
211→    const result = await query<PrivacyRequest>(
212→      `UPDATE privacy_requests
213→       SET status = $2,
214→           assigned_to = $3,
215→           notes = COALESCE($4, notes),
216→           resolution_notes = COALESCE($5, resolution_notes),
217→           updated_at = NOW()
218→       WHERE id = $1::uuid
219→       RETURNING id::text, request_type AS "requestType", status, subject_reference AS "subjectReference",
220→                 created_by AS "createdBy", assigned_to AS "assignedTo", notes,
221→                 resolution_notes AS "resolutionNotes", created_at AS "createdAt", updated_at AS "updatedAt"`,
222→      [id, status, assignedTo, notes, resolutionNotes],
223→    );
224→    if (!result.rows[0]) return errorResponse("Privacy request not found", 404);
225→    return jsonResponse(result.rows[0], { status: 200 });
226→  } catch (error) {
227→    captureServerException(error, { route: "privacy_patch" });
228→    throw error;
229→  }
230→}
