  1→import type { SubmissionInput } from '../../shared/types';
  2→
  3→const DB_NAME = 'adl_offline_queue';
  4→const STORE_NAME = 'submission_queue';
  5→const SYNC_ERROR_STORE_NAME = 'submission_sync_errors';
  6→const DB_VERSION = 2;
  7→const SESSION_SYNC_COUNT_KEY = 'adl_queue_session_synced';
  8→const MAX_QUEUE_ITEMS = 75;
  9→const MAX_QUEUE_RETRY_COUNT = 6;
 10→const MAX_QUEUE_ITEM_AGE_MS = 72 * 60 * 60 * 1000;
 11→
 12→export type QueueStatus = 'pending' | 'syncing' | 'failed' | 'synced';
 13→
 14→export interface QueueItem {
 15→  id: string;
 16→  idempotencyKey: string;
 17→  payload: SubmissionInput;
 18→  status: QueueStatus;
 19→  attempts: number;
 20→  retryCount: number;
 21→  nextRetryAt?: string;
 22→  lastError?: string;
 23→  createdAt: string;
 24→  updatedAt: string;
 25→}
 26→
 27→export interface SyncErrorRecord {
 28→  id: string;
 29→  queueItemId: string;
 30→  message: string;
 31→  createdAt: string;
 32→  payloadSummary: {
 33→    eventType: SubmissionInput['eventType'];
 34→    category: SubmissionInput['category'];
 35→    pointId?: string;
 36→    location?: SubmissionInput['location'];
 37→  };
 38→}
 39→
 40→export interface QueueSyncSummary {
 41→  synced: number;
 42→  failed: number;
 43→  syncedIds: string[];
 44→  failedIds: string[];
 45→  permanentFailures: number;
 46→  permanentFailureIds: string[];
 47→  permanentFailureMessages: string[];
 48→  remaining: number;
 49→}
 50→
 51→export interface QueueSnapshot {
 52→  pending: number;
 53→  failed: number;
 54→  total: number;
 55→  synced: number;
 56→  queuedFailed: number;
 57→  rejected: number;
 58→  storageBytes: number;
 59→}
 60→
 61→type QueueSnapshotListener = (snapshot: QueueSnapshot) => void;
 62→
 63→const queueSnapshotListeners = new Set<QueueSnapshotListener>();
 64→
 65→function toQueueErrorInfo(error: unknown): { message: string; retryable: boolean } {
 66→  const fallback = 'Unable to sync queued submission';
 67→  if (error instanceof Error) {
 68→    const withRetryable = error as Error & { retryable?: unknown };
 69→    const retryable = typeof withRetryable.retryable === 'boolean' ? withRetryable.retryable : true;
 70→    const message = error.message?.trim() || fallback;
 71→    return { message, retryable };
 72→  }
 73→  return { message: String(error ?? fallback), retryable: true };
 74→}
 75→
 76→function ensureIndexedDb(): IDBFactory {
 77→  if (typeof indexedDB === 'undefined') {
 78→    throw new Error('IndexedDB is not available');
 79→  }
 80→  return indexedDB;
 81→}
 82→
 83→function isStaleItem(item: QueueItem, now = Date.now()): boolean {
 84→  return now - new Date(item.createdAt).getTime() > MAX_QUEUE_ITEM_AGE_MS;
 85→}
 86→
 87→function requestToPromise<T>(request: IDBRequest<T>): Promise<T> {
 88→  return new Promise((resolve, reject) => {
 89→    request.onsuccess = () => resolve(request.result);
 90→    request.onerror = () => reject(request.error);
 91→  });
 92→}
 93→
 94→function transactionDone(tx: IDBTransaction): Promise<void> {
 95→  return new Promise((resolve, reject) => {
 96→    tx.oncomplete = () => resolve();
 97→    tx.onerror = () => reject(tx.error);
 98→    tx.onabort = () => reject(tx.error ?? new Error('IndexedDB transaction aborted'));
 99→  });
100→}
101→
102→function readSyncedCount(): number {
103→  try {
104→    const raw = window.localStorage.getItem(SESSION_SYNC_COUNT_KEY);
105→    const parsed = Number(raw ?? '0');
106→    return Number.isFinite(parsed) ? Math.max(0, Math.floor(parsed)) : 0;
107→  } catch {
108→    return 0;
109→  }
110→}
111→
112→function writeSyncedCount(value: number): void {
113→  try {
114→    window.localStorage.setItem(SESSION_SYNC_COUNT_KEY, String(Math.max(0, Math.floor(value))));
115→  } catch {
116→    // Ignore storage failures; queue persistence still works via IndexedDB.
117→  }
118→}
119→
120→function incrementSyncedCount(value: number): void {
121→  if (!Number.isFinite(value) || value <= 0) return;
122→  writeSyncedCount(readSyncedCount() + Math.floor(value));
123→}
124→
125→async function emitQueueSnapshot(): Promise<void> {
126→  if (queueSnapshotListeners.size === 0) return;
127→  try {
128→    const snapshot = await getQueueSnapshot();
129→    queueSnapshotListeners.forEach((listener) => listener(snapshot));
130→  } catch {
131→    // Snapshot reads should never break queue operations.
132→  }
133→}
134→
135→export function subscribeQueueSnapshot(listener: QueueSnapshotListener): () => void {
136→  queueSnapshotListeners.add(listener);
137→  void getQueueSnapshot().then(listener).catch(() => undefined);
138→  return () => {
139→    queueSnapshotListeners.delete(listener);
140→  };
141→}
