143→async function openDb(): Promise<IDBDatabase> {
144→  const db = ensureIndexedDb();
145→  return await new Promise<IDBDatabase>((resolve, reject) => {
146→    const request = db.open(DB_NAME, DB_VERSION);
147→    request.onupgradeneeded = () => {
148→      const nextDb = request.result;
149→      if (!nextDb.objectStoreNames.contains(STORE_NAME)) {
150→        nextDb.createObjectStore(STORE_NAME, { keyPath: 'id' });
151→      }
152→      if (!nextDb.objectStoreNames.contains(SYNC_ERROR_STORE_NAME)) {
153→        nextDb.createObjectStore(SYNC_ERROR_STORE_NAME, { keyPath: 'id' });
154→      }
155→    };
156→    request.onsuccess = () => resolve(request.result);
157→    request.onerror = () => reject(request.error);
158→  });
159→}
160→
161→async function putItem(item: QueueItem, options: { notify?: boolean } = {}): Promise<void> {
162→  const db = await openDb();
163→  const tx = db.transaction(STORE_NAME, 'readwrite');
164→  tx.objectStore(STORE_NAME).put(item);
165→  await transactionDone(tx);
166→  db.close();
167→  if (options.notify !== false) await emitQueueSnapshot();
168→}
169→
170→async function deleteSyncErrorRecordsByQueueItemId(queueItemId: string, options: { notify?: boolean } = {}): Promise<void> {
171→  const db = await openDb();
172→  const tx = db.transaction(SYNC_ERROR_STORE_NAME, 'readwrite');
173→  const store = tx.objectStore(SYNC_ERROR_STORE_NAME);
174→  const request = store.getAll();
175→  const result = await requestToPromise(request);
176→  for (const record of result as SyncErrorRecord[]) {
177→    if (record.queueItemId === queueItemId) {
178→      store.delete(record.id);
179→    }
180→  }
181→  await transactionDone(tx);
182→  db.close();
183→  if (options.notify !== false) await emitQueueSnapshot();
184→}
