186→export async function enqueueSubmission(payload: SubmissionInput): Promise<QueueItem> {
187→  const existingItems = await listQueueItems();
188→  if (existingItems.length >= MAX_QUEUE_ITEMS) {
189→    throw new Error(`Offline queue is full (${MAX_QUEUE_ITEMS} items). Sync or clear older items before adding more.`);
190→  }
191→  const now = new Date().toISOString();
192→  const item: QueueItem = {
193→    id: crypto.randomUUID(),
194→    idempotencyKey: crypto.randomUUID(),
195→    payload,
196→    status: 'pending',
197→    attempts: 0,
198→    retryCount: 0,
199→    createdAt: now,
200→    updatedAt: now,
201→  };
202→  await putItem(item);
203→  return item;
204→}
