206→export async function listQueueItems(): Promise<QueueItem[]> {
207→  const db = await openDb();
208→  const tx = db.transaction(STORE_NAME, 'readonly');
209→  const request = tx.objectStore(STORE_NAME).getAll();
210→  const result = await requestToPromise(request);
211→  await transactionDone(tx);
212→  db.close();
213→  return (result as QueueItem[]).sort((a, b) => new Date(a.createdAt).getTime() - new Date(b.createdAt).getTime());
214→}
