216→export async function getQueueItem(id: string): Promise<QueueItem | null> {
217→  const db = await openDb();
218→  const tx = db.transaction(STORE_NAME, 'readonly');
219→  const request = tx.objectStore(STORE_NAME).get(id);
220→  const result = await requestToPromise(request);
221→  await transactionDone(tx);
222→  db.close();
223→  return (result as QueueItem | undefined) ?? null;
