226→async function updateItem(
227→  id: string,
228→  updater: (item: QueueItem) => QueueItem,
229→  options: { notify?: boolean } = {},
230→): Promise<QueueItem | null> {
231→  const db = await openDb();
232→  const updated = await new Promise<QueueItem | null>((resolve, reject) => {
233→    const tx = db.transaction(STORE_NAME, 'readwrite');
234→    const store = tx.objectStore(STORE_NAME);
235→    let nextItem: QueueItem | null = null;
236→    const getRequest = store.get(id);
237→    getRequest.onsuccess = () => {
238→      const existing = getRequest.result as QueueItem | undefined;
239→      if (!existing) return;
240→      nextItem = updater(existing);
241→      store.put(nextItem);
242→    };
243→    getRequest.onerror = () => reject(getRequest.error);
244→    tx.oncomplete = () => resolve(nextItem);
245→    tx.onerror = () => reject(tx.error);
246→    tx.onabort = () => reject(tx.error ?? new Error('IndexedDB transaction aborted'));
247→  });
248→  db.close();
249→  if (options.notify !== false) await emitQueueSnapshot();
250→  return updated;
251→}
