253→async function removeItem(id: string, options: { notify?: boolean } = {}): Promise<void> {
254→  const db = await openDb();
255→  const tx = db.transaction(STORE_NAME, 'readwrite');
256→  tx.objectStore(STORE_NAME).delete(id);
257→  await transactionDone(tx);
258→  db.close();
259→  if (options.notify !== false) await emitQueueSnapshot();
260→}
