271→export async function listSyncErrorRecords(): Promise<SyncErrorRecord[]> {
272→  const db = await openDb();
273→  const tx = db.transaction(SYNC_ERROR_STORE_NAME, 'readonly');
274→  const request = tx.objectStore(SYNC_ERROR_STORE_NAME).getAll();
