337→export async function getQueueSnapshot(): Promise<QueueSnapshot> {
338→  const [items, syncErrors] = await Promise.all([listQueueItems(), listSyncErrorRecords()]);
339→  const pending = items.filter((item) => item.status === 'pending' || item.status === 'syncing').length;
340→  const queuedFailed = items.filter((item) => item.status === 'failed').length;
341→  const rejected = syncErrors.length;
342→  const storageBytes = new TextEncoder().encode(JSON.stringify(items)).length;
343→  return {
344→    pending,
345→    failed: queuedFailed + rejected,
346→    total: items.length,
347→    synced: readSyncedCount(),
348→    queuedFailed,
349→    rejected,
350→    storageBytes,
351→  };
352→}
