354→export async function getQueueStats(): Promise<{ pending: number; failed: number; total: number }> {
355→  const snapshot = await getQueueSnapshot();
356→  return {
357→    pending: snapshot.pending,
358→    failed: snapshot.failed,
359→    total: snapshot.total,
360→  };
361→}
362→
363→export async function flushOfflineQueue(
364→  sendFn: (payload: SubmissionInput, options?: { idempotencyKey?: string }) => Promise<void>,
365→): Promise<QueueSyncSummary> {
366→  const items = await listQueueItems();
367→  const now = Date.now();
368→  let synced = 0;
369→  let failed = 0;
370→  const syncedIds: string[] = [];
371→  const failedIds: string[] = [];
372→  let permanentFailures = 0;
373→  const permanentFailureIds: string[] = [];
374→  const permanentFailureMessages = new Set<string>();
375→
376→  for (const item of items) {
377→    if (isStaleItem(item, now)) {
378→      permanentFailures += 1;
379→      permanentFailureIds.push(item.id);
380→      permanentFailureMessages.add('Queued submission expired before it could be synced');
381→      await putSyncErrorRecord(
382→        {
383→          id: crypto.randomUUID(),
384→          queueItemId: item.id,
385→          message: 'Queued submission expired before it could be synced',
386→          createdAt: new Date().toISOString(),
387→          payloadSummary: {
388→            eventType: item.payload.eventType,
389→            category: item.payload.category,
390→            pointId: item.payload.pointId,
391→            location: item.payload.location,
392→          },
393→        },
394→        { notify: false },
395→      );
396→      await removeItem(item.id, { notify: false });
397→      continue;
398→    }
399→
400→    if (item.nextRetryAt && new Date(item.nextRetryAt).getTime() > now) {
401→      failed += 1;
402→      failedIds.push(item.id);
403→      continue;
404→    }
405→
406→    await updateItem(
407→      item.id,
408→      (current) => ({
409→        ...current,
410→        status: 'syncing',
411→        attempts: current.attempts + 1,
412→        updatedAt: new Date().toISOString(),
413→      }),
414→      { notify: false },
415→    );
416→
417→    try {
418→      await sendFn(item.payload, { idempotencyKey: item.idempotencyKey });
419→      await removeItem(item.id, { notify: false });
420→      await deleteSyncErrorRecordsByQueueItemId(item.id, { notify: false });
421→      synced += 1;
422→      syncedIds.push(item.id);
423→    } catch (error) {
424→      const details = toQueueErrorInfo(error);
425→      if (details.retryable) {
426→        const retryCount = (item.retryCount ?? 0) + 1;
427→        if (retryCount > MAX_QUEUE_RETRY_COUNT) {
428→          permanentFailures += 1;
429→          permanentFailureIds.push(item.id);
430→          permanentFailureMessages.add(details.message);
431→          await putSyncErrorRecord(
432→            {
433→              id: crypto.randomUUID(),
434→              queueItemId: item.id,
435→              message: details.message,
436→              createdAt: new Date().toISOString(),
437→              payloadSummary: {
438→                eventType: item.payload.eventType,
439→                category: item.payload.category,
440→                pointId: item.payload.pointId,
441→                location: item.payload.location,
442→              },
443→            },
444→            { notify: false },
445→          );
446→          await removeItem(item.id, { notify: false });
447→          continue;
448→        }
449→        failed += 1;
450→        failedIds.push(item.id);
451→        const baseDelay = Math.min(30000, 1000 * Math.pow(2, retryCount));
452→        const jitter = Math.random() * 1000;
453→        const nextRetryAt = new Date(now + baseDelay + jitter).toISOString();
454→        await updateItem(
455→          item.id,
456→          (current) => ({
457→            ...current,
458→            status: 'failed',
459→            retryCount,
460→            nextRetryAt,
461→            updatedAt: new Date().toISOString(),
462→            lastError: details.message,
463→          }),
464→          { notify: false },
465→        );
466→        continue;
467→      }
468→
469→      permanentFailures += 1;
470→      permanentFailureIds.push(item.id);
471→      permanentFailureMessages.add(details.message);
472→      await putSyncErrorRecord(
473→        {
474→          id: crypto.randomUUID(),
475→          queueItemId: item.id,
476→          message: details.message,
477→          createdAt: new Date().toISOString(),
478→          payloadSummary: {
479→            eventType: item.payload.eventType,
480→            category: item.payload.category,
481→            pointId: item.payload.pointId,
482→            location: item.payload.location,
483→          },
484→        },
485→        { notify: false },
486→      );
487→      await removeItem(item.id, { notify: false });
488→    }
489→  }
490→
491→  if (synced > 0) {
492→    incrementSyncedCount(synced);
493→  }
494→
495→  const remaining = (await listQueueItems()).length;
496→  await emitQueueSnapshot();
497→  return {
498→    synced,
499→    failed,
500→    syncedIds,
501→    failedIds,
502→    permanentFailures,
503→    permanentFailureIds,
504→    permanentFailureMessages: Array.from(permanentFailureMessages),
505→    remaining,
506→  };
507→}
