22→  const body = validation.data;
23→  const rawIdentifier = body?.identifier ?? body?.email;
24→  const normalizedIdentifier = normalizeIdentifier(rawIdentifier);
25→  const password = body?.password;
26→  const name = body?.name?.trim() ?? "";
