39→    const profile: UserProfile = {
40→      id: identifier,
41→      name: name || inferDefaultDisplayName(identifier),
42→      email: normalizedIdentifier.type === "email" ? identifier : null,
43→      phone: normalizedIdentifier.type === "phone" ? identifier : null,
