15→export async function reserveIdempotencyKey(input: {
16→  userId: string;
17→  idempotencyKey: string;
18→  requestHash: string;
19→}): Promise<
20→  | { status: "reserved" }
21→  | { status: "replay"; eventId: string | null; responseStatus: number }
22→  | { status: "conflict" }
23→> {
24→  const existing = await query<{ request_hash: string; response_event_id: string | null; response_status: number }>(
25→    `SELECT request_hash, response_event_id::text, response_status
26→     FROM submission_idempotency_keys
27→     WHERE user_id = $1
28→       AND idempotency_key = $2
29→     LIMIT 1`,
30→    [input.userId, input.idempotencyKey],
31→  );
32→
33→  const row = existing.rows[0];
34→  if (row) {
35→    if (row.request_hash !== input.requestHash) {
36→      return { status: "conflict" };
37→    }
38→    if (!row.response_event_id) {
39→      await query(
40→        `UPDATE submission_idempotency_keys
41→         SET last_seen_at = NOW()
42→         WHERE user_id = $1
43→           AND idempotency_key = $2`,
44→        [input.userId, input.idempotencyKey],
45→      );
46→      return { status: "reserved" };
47→    }
48→    return {
49→      status: "replay",
50→      eventId: row.response_event_id,
51→      responseStatus: Number(row.response_status ?? 201),
52→    };
53→  }
54→
55→  await query(
56→    `INSERT INTO submission_idempotency_keys (user_id, idempotency_key, request_hash)
57→     VALUES ($1, $2, $3)`,
58→    [input.userId, input.idempotencyKey, input.requestHash],
59→  );
60→  return { status: "reserved" };
61→}
