214→export async function signOut(): Promise<void> {
215→  const csrfToken = await getCsrfToken();
216→  const body = new URLSearchParams();
217→  body.set("csrfToken", csrfToken);
218→  body.set("callbackUrl", window.location.origin);
219→  body.set("json", "true");
220→
221→  const response = await apiFetch("/api/auth/signout", {
222→    method: "POST",
223→    headers: { "Content-Type": "application/x-www-form-urlencoded" },
224→    body,
225→  });
226→  if (!response.ok) {
227→    const { message } = await extractResponseErrorPayload(response, DEFAULT_SIGN_OUT_ERROR);
228→    const retryable = response.status >= 500;
229→    throw new AuthClientError(retryable ? "auth_unavailable" : "request_error", message, { retryable });
230→  }
231→}
