233→export async function registerWithCredentials(identifier: string, password: string, name?: string): Promise<void> {
234→  const normalizedIdentifier = normalizeIdentifier(identifier)?.value ?? identifier.trim();
235→  const response = await apiFetch("/api/auth/register", {
236→    method: "POST",
237→    headers: { "Content-Type": "application/json" },
238→    body: JSON.stringify({ identifier: normalizedIdentifier, email: normalizedIdentifier, password, name }),
239→  });
240→
241→  if (!response.ok) {
242→    const { message, code } = await extractResponseErrorPayload(response, DEFAULT_SIGN_UP_ERROR);
243→    if (response.status === 409) {
244→      throw new AuthClientError("registration_conflict", message);
245→    }
246→    if (response.status === 400) {
247→      throw new AuthClientError("validation_error", message);
248→    }
249→    if (response.status === 503 && code === "storage_unavailable") {
250→      throw new AuthClientError("storage_unavailable", message, { retryable: true });
251→    }
252→    const retryable = response.status >= 500;
253→    throw new AuthClientError(retryable ? "auth_unavailable" : "request_error", message, { retryable });
254→  }
255→}
