257→export async function signInWithGoogle(): Promise<void> {
258→  const csrfToken = await getCsrfToken();
259→  const form = document.createElement("form");
260→  form.method = "POST";
261→  form.action = buildUrl("/api/auth/signin/google");
262→  form.style.display = "none";
263→
264→  const addField = (name: string, value: string) => {
265→    const input = document.createElement("input");
266→    input.type = "hidden";
267→    input.name = name;
268→    input.value = value;
269→    form.appendChild(input);
270→  };
271→
272→  addField("csrfToken", csrfToken);
273→  addField("callbackUrl", window.location.origin);
274→
275→  document.body.appendChild(form);
276→  form.submit();
277→}
