 1→export async function executeAppWipe(): Promise<void> {
 2→  if (typeof indexedDB !== "undefined" && typeof indexedDB.databases === "function") {
 3→    const databases = await indexedDB.databases();
 4→    await Promise.all(
 5→      databases
 6→        .map((entry) => entry.name)
 7→        .filter((name): name is string => Boolean(name))
 8→        .map(async (name) => {
 9→          indexedDB.deleteDatabase(name);
10→        }),
11→    );
12→  }
13→
14→  try {
15→    localStorage.clear();
16→    sessionStorage.clear();
17→  } catch {
18→    // Ignore browser storage access failures.
19→  }
20→
21→  if (typeof navigator !== "undefined" && "serviceWorker" in navigator) {
22→    const registrations = await navigator.serviceWorker.getRegistrations();
23→    await Promise.all(registrations.map((registration) => registration.unregister()));
24→  }
25→
26→  if (typeof caches !== "undefined") {
27→    const cacheNames = await caches.keys();
28→    await Promise.all(cacheNames.map((cacheName) => caches.delete(cacheName)));
29→  }
30→
31→  window.location.href = "/api/auth/signin?wipe=1";
32→}
